import { useEffect, useState } from "react";
function App() {
  let [users, setUsers] = useState([])
  useEffect(() => {
    let loadusers = async() => {
      try {
        let res = await fetch("http://localhost:5000/login")
        let data = await res.json()
        setUsers(data)
      }catch{
        console.log("Error while fetching")
      }
    }
    loadusers()
  })
  return<>
    <div>
      <p>Login into your acccount</p>
      <p>Username</p>
      <input/>
      <p>Password</p>
      <input/>
      <button>Login</button>
      <p></p>
    </div>
  </>
}
export default App
